import{_ as a,c as n,a as r,o as d}from"./app-CM3AmF9G.js";const c={};function t(i,e){return d(),n("div",null,e[0]||(e[0]=[r('<blockquote><p>All in AI，看见未来。 每天精选最值得读的AI文章，帮你筛掉时代的噪音。 以简讯见广度，以深读见洞察。 技术、趋势、思考，一站式掌握AI世界。 欢迎关注公众号「AI Reading Hub」，获取更多AI资讯和技术文章。</p></blockquote><h1 id="_2026-04-13-资讯日报" tabindex="-1"><a class="header-anchor" href="#_2026-04-13-资讯日报"><span>2026-04-13 资讯日报</span></a></h1><h2 id="新闻资讯" tabindex="-1"><a class="header-anchor" href="#新闻资讯"><span>新闻资讯</span></a></h2><h3 id="美国报告-中国开源模型超越美国" tabindex="-1"><a class="header-anchor" href="#美国报告-中国开源模型超越美国"><span>美国报告：中国开源模型超越美国</span></a></h3><p>美国ATOM报告：2025年夏中国开源语言模型全面超越美国，下载、使用量优势明显。Qwen称霸，DeepSeek在大模型领域领先。美国新势力追赶，报告引入新指标评模型热度。<a href="https://mp.weixin.qq.com/s?__biz=Mzg3Mzg5MjY3Nw==&amp;chksm=cf3dd83aa348f1faccaf1f2bdd99f6e22712bde3647c9f8e6c751112969205f3c098bde79452&amp;idx=1&amp;mid=2247526127&amp;sn=e62cf6ad26268c401fec898094de4810#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="_97小伙余琛研发可断腿奔跑的模块化机器人" tabindex="-1"><a class="header-anchor" href="#_97小伙余琛研发可断腿奔跑的模块化机器人"><span>97小伙余琛研发可断腿奔跑的模块化机器人</span></a></h3><p>美国西北大学余琛团队研发模块化机器人，由独立智能腿模块构成，能自由组合，可适应断腿等损伤，在灾难救援、太空探索等领域有应用前景，敏捷与重构兼得。<a href="https://mp.weixin.qq.com/s?__biz=MzA3NTIyODUzNA==&amp;chksm=86ef6caaca5dd75d2b49ba6284329db751addc8d92458f3d1bb71e3ea8988094f97b4d513984&amp;idx=1&amp;mid=2649794020&amp;sn=d10fc5be3678c3f816344f73827c3fba#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="奥特曼豪宅再遭袭-ai末日论者发难" tabindex="-1"><a class="header-anchor" href="#奥特曼豪宅再遭袭-ai末日论者发难"><span>奥特曼豪宅再遭袭，AI末日论者发难</span></a></h3><p>奥特曼豪宅两次遭袭，此前有人扔燃烧弹，后又有人开枪。他发文感化仇恨者无果。AI末日论者认为科技大佬推动AI有风险，呼吁停建数据中心、终止前沿研究。<a href="https://mp.weixin.qq.com/s?__biz=MzI3MTA0MTk1MA==&amp;chksm=f07c81efa86d09586334b02c6df5a847ffb5d58491ca53e65acfdba8dce894b35d2684e451a5&amp;idx=1&amp;mid=2652691500&amp;sn=abb8bfb851847532d41e284500debae9#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="自变量-戳破具身智能行业-气泡" tabindex="-1"><a class="header-anchor" href="#自变量-戳破具身智能行业-气泡"><span>自变量：戳破具身智能行业‘气泡’</span></a></h3><p>自变量机器人：4月21日发布会将戳破具身智能行业‘气泡’。该行业存在四大认知偏差，‘拐点时刻’需大脑能力突破、场景稳定运行、跑通ROI闭环，应回归理性，深耕技术与落地。<a href="https://mp.weixin.qq.com/s?__biz=MzA5ODEzMjIyMA==&amp;chksm=912b64b251fd27ebce5e523351534fef50441d2295fb986421c97de3e0e1477a1ac4a41a5d88&amp;idx=1&amp;mid=2247733176&amp;sn=8f9a10d554d274f162dd75486740296f#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="hermes-agent爆火-新推理方法问世" tabindex="-1"><a class="header-anchor" href="#hermes-agent爆火-新推理方法问世"><span>Hermes Agent爆火，新推理方法问世</span></a></h3><p>Hermes Agent爆火，GitHub星数众多，还接入微信。其署名论文提出Autoreason，指出传统‘自我优化’有幻觉瑕疵等问题，小模型配合该方法表现出色，标志AI推理转向‘结构出效率’。<a href="https://mp.weixin.qq.com/s?__biz=MzI3MTA0MTk1MA==&amp;chksm=f0b97eed270e932e7c17a0109170e5f722def12d7691de45285a388dff52baec432fefe6e891&amp;idx=2&amp;mid=2652691500&amp;sn=d81b22ca4e016f9670e261b677d6f614#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="极佳视界获大额融资-领跑世界模型赛道" tabindex="-1"><a class="header-anchor" href="#极佳视界获大额融资-领跑世界模型赛道"><span>极佳视界获大额融资，领跑世界模型赛道</span></a></h3><p>极佳视界：短期内连获两轮大额融资，估值超百亿。作为世界模型赛道领先者，产品在多领域落地，还计划年内通过效率提升，率先到达具身智能的GPT - 3时刻。<a href="https://mp.weixin.qq.com/s?__biz=MzA5ODEzMjIyMA==&amp;chksm=91483a3148b5a5c2dec5aa63d7160492beb9d37ba693e90b0fea9e140c843d9bbb143402479a&amp;idx=1&amp;mid=2247733167&amp;sn=afa88ceb42b9592c75d203ff6b08fbb4#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h2 id="产品应用" tabindex="-1"><a class="header-anchor" href="#产品应用"><span>产品应用</span></a></h2><h3 id="claude-code省token指南大揭秘" tabindex="-1"><a class="header-anchor" href="#claude-code省token指南大揭秘"><span>Claude Code省Token指南大揭秘</span></a></h3><p>宝玉：Claude Code配额消耗快，因模型每次都重读输入。可利用提示缓存省Token，遵循如继续热缓存会话、复杂任务一次做对等策略，还给出操作规则及委派工作思路。<a href="https://mp.weixin.qq.com/s?__biz=Mzk1NzgxMjQ0OA==&amp;chksm=c23a835a313cd743dbec13cf3d5a401a6b116f4d13d2b78861e583b6c71690a5028385df5526&amp;idx=1&amp;mid=2247494566&amp;sn=2b2e292517055809922eeb459b725d6d#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="libtv支持seedance-2-0真人模式-效果炸裂" tabindex="-1"><a class="header-anchor" href="#libtv支持seedance-2-0真人模式-效果炸裂"><span>LibTV支持Seedance 2.0真人模式，效果炸裂</span></a></h3><p>作者实测：LibTV支持Seedance 2.0真人生成视频，操作简单，效果惊艳。真人出镜有多种实用场景，工具工作流高效，价格有优惠，可用性拉满。<a href="https://mp.weixin.qq.com/s?__biz=Mzg3MTkxMjYzOA==&amp;chksm=cf73c89ebbafc8f2f4e86fc851cbee8b9c5f3f2d1f8e5448296793298b66c3c0f0288427ca7e&amp;idx=1&amp;mid=2247513991&amp;sn=c85d9e86ada8dfd690b8d5dd11619fb0#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="明略-mano-p-1-0-引领个性化-ai-新时代" tabindex="-1"><a class="header-anchor" href="#明略-mano-p-1-0-引领个性化-ai-新时代"><span>明略 Mano-P 1.0：引领个性化 AI 新时代</span></a></h3><p>明略科技赵晨旭：当下处于 AGI 与 Personalized AI 时代交界。Mano-P 1.0 模型在多榜单领先，通过技术突破实现本地运行，开源是为让更多人用上，设想用于全自动应用构建。<a href="https://mp.weixin.qq.com/s?__biz=MzA3MzI4MjgzMw==&amp;chksm=85b8ec80945c608f6ab701d09a552ec7c3235ee799b6db43b70b23dd05fc565b32b7b77abf9e&amp;idx=1&amp;mid=2651027314&amp;sn=5f962ab9416c2eee0c4769a51057ced7#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="ai-agent应用-理想美好-现实骨感" tabindex="-1"><a class="header-anchor" href="#ai-agent应用-理想美好-现实骨感"><span>AI Agent应用：理想美好，现实骨感</span></a></h3><p>作者：使用Coding Agent有诸多坑。部分模型体验差，自然语言模糊阻碍长程工作，还有方案权衡、多Agent合作等问题。虽Agent前景好，但目前还不能替代人类复杂工作。<a href="https://mp.weixin.qq.com/s?__biz=MzA4MjY4NTk0NQ==&amp;chksm=9eae39cfa7350a6cc4a8f279231a28a63eae423307514c4e4d02dbde1e991fe57094e76e4c6d&amp;idx=1&amp;mid=2247531306&amp;sn=6867158f184b1830d24befb8997a51a0#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="harness-monitor-看住多-agent-代码质量" tabindex="-1"><a class="header-anchor" href="#harness-monitor-看住多-agent-代码质量"><span>Harness Monitor：看住多 Agent 代码质量</span></a></h3><p>Phodal：多 Agent 同时写代码成日常，但质量把控变难。Harness Monitor 从 Git 视角出发，解决‘谁改了什么’等问题，将多 Agent 开发接入可观察、可治理闭环，保护代码演化质量。<a href="https://mp.weixin.qq.com/s?__biz=MjM5Mjg4NDMwMA==&amp;chksm=bc2d2a09604c6a487645f0f57bd6913b59ae2ff352ffdeee112b82b1a9a3c40f537d55fcde47&amp;idx=1&amp;mid=2652980449&amp;sn=0292829ac04841867df6362802966e9b#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h2 id="推荐文章" tabindex="-1"><a class="header-anchor" href="#推荐文章"><span>推荐文章</span></a></h2><h3 id="tokens烧钱-四层模型组合来救场" tabindex="-1"><a class="header-anchor" href="#tokens烧钱-四层模型组合来救场"><span>Tokens烧钱？四层模型组合来救场</span></a></h3><p>网友gkisokay：将2026年主流模型分四档，给出多模型策略。还提供路由策略与部署建议，指出单模型依赖危险，呼吁模型商形成良性价格体系。<a href="https://mp.weixin.qq.com/s?__biz=MzA5MTIxNTY4MQ==&amp;chksm=860e98e45cad6e2fed1760477b64faf4cd9db5b3c9feda8fb8a58ba95cda685c849497436dc7&amp;idx=1&amp;mid=2461159312&amp;sn=c1ff8e15e3bf735d09c0e8e368c7a6bc#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="卡兹克-横纵分析法半小时搞懂陌生领域" tabindex="-1"><a class="header-anchor" href="#卡兹克-横纵分析法半小时搞懂陌生领域"><span>卡兹克：横纵分析法半小时搞懂陌生领域</span></a></h3><p>数字生命卡兹克：分享用2年的横纵分析法，结合学术视角和商业思路，有Prompt和Skill版本并开源。虽有局限，但能半小时搭建认知框架，助快速入门陌生领域，好奇才是研究关键。<a href="https://mp.weixin.qq.com/s?__biz=MzIyMzA5NjEyMA==&amp;chksm=f16f954bada7f297b004c228beccd7225c9b06d380a285626db41a903281d54cb19305006f1a&amp;idx=1&amp;mid=2647681493&amp;sn=76f444ffcb134e6e8763d03fe03ae5ca#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="学者解析coding-agent底层逻辑" tabindex="-1"><a class="header-anchor" href="#学者解析coding-agent底层逻辑"><span>学者解析Coding Agent底层逻辑</span></a></h3><p>Sebastian Raschka：编码智能体受关注，因其周边支撑系统重要。介绍大模型、推理模型与智能体关系，阐述编码智能体六大核心组件，如代码库上下文、提示词缓存等，还对比了与OpenClaw的差异。<a href="https://mp.weixin.qq.com/s?__biz=MzA3MzI4MjgzMw==&amp;chksm=85193374418f8e3064de46f5160ad536539f24184d17c1e40e889c88257dd64ea8c4fbfc198c&amp;idx=2&amp;mid=2651027200&amp;sn=bd8cae56fa12192c25cceca6fc3e28e1#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="hermes-agent-实现agent自学习新突破" tabindex="-1"><a class="header-anchor" href="#hermes-agent-实现agent自学习新突破"><span>Hermes-Agent：实现Agent自学习新突破</span></a></h3><p>秋山墨客：现有Agent大多缺乏自学习能力，Hermes - Agent不一样，有Skill自学习机制和强化学习训练闭环。用代码审计任务演示其自学习，解析了机制，为生产级Agent系统提供新思路。<a href="https://mp.weixin.qq.com/s?__biz=Mzk1NzQ1ODk5NQ==&amp;chksm=c2b93cb4cc0f34e811eaf4c7290b2d42cd32f89bdde13a318f503bc363b7415749323e751236&amp;idx=1&amp;mid=2247525606&amp;sn=d6a1f28a7e08062c32e0370ab6cfac88#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h2 id="开源动态" tabindex="-1"><a class="header-anchor" href="#开源动态"><span>开源动态</span></a></h2><h3 id="hermes-agent-比openclaw更快更灵活的ai-agent" tabindex="-1"><a class="header-anchor" href="#hermes-agent-比openclaw更快更灵活的ai-agent"><span>Hermes Agent：比OpenClaw更快更灵活的AI Agent</span></a></h3><p>Nous Research：Hermes Agent是会成长的AI智能体，有六大特性，支持换模型，更新超多数商业产品，还能一键安装，比OpenClaw更快更灵活。<a href="https://mp.weixin.qq.com/s?__biz=MzkwMjQ0NzI0OQ==&amp;chksm=c1afcf4616c8adf24209d5ac94a0e35801fb7eb051b956c16d485e407d002d91ac54b04506b7&amp;idx=1&amp;mid=2247505877&amp;sn=49e6071cd8dd8fe7f05495c378235978#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="黄叔开源skill管理神器skill-hub" tabindex="-1"><a class="header-anchor" href="#黄叔开源skill管理神器skill-hub"><span>黄叔开源Skill管理神器Skill Hub</span></a></h3><p>AI产品黄叔：因社群用户和自己管理Skill有困扰，用Claude Code开发Skill Hub并开源。经用户反馈迭代，增加相似检测、Git同步等功能，一行命令就能用。<a href="https://mp.weixin.qq.com/s?__biz=MjM5ODU1MzQzOQ==&amp;chksm=b0a693cb4213e341c513ced0f5996a8d4d3b00c7e956a3ee854ae9e87996a012f40648c94f5c&amp;idx=1&amp;mid=2451429465&amp;sn=3ed12d7bb32f2e664a231a0d1b545572#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="飞樰深度解析openclaw设计哲学" tabindex="-1"><a class="header-anchor" href="#飞樰深度解析openclaw设计哲学"><span>飞樰深度解析OpenClaw设计哲学</span></a></h3><p>飞樰：OpenClaw将Agent关键技术集成升华，在Prompt、Context和Harness维度有诸多可学之处。如Prompt动态组装、Context多机制管理、Harness设约束引导，为构建Agent系统提供了优秀范本。<a href="https://mp.weixin.qq.com/s?__biz=MzIzOTU0NTQ0MA==&amp;chksm=e858978e815997d37ba9933ef407eada0e1dc73b0eef741c09381adb7cee18301ee42569faeb&amp;idx=1&amp;mid=2247559511&amp;sn=64e933b0264e47f0940e693e315e0c82#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="autosota-让科研摆脱-增量式优化" tabindex="-1"><a class="header-anchor" href="#autosota-让科研摆脱-增量式优化"><span>AutoSOTA：让科研摆脱“增量式优化”</span></a></h3><p>清华与中关村学院联合发布AutoSOTA项目，接管AI科研中繁琐的实验迭代。一周发现105个SOTA模型，让AI负责性能优化，人类专注原创，推动科研回归追求原创突破的起点。<a href="https://mp.weixin.qq.com/s?__biz=Mzg3Mzg5MjY3Nw==&amp;chksm=cff101e2df8d2e77c1205dddb52249418132a87e666f77ae637e9f9b255742e927774901206e&amp;idx=2&amp;mid=2247526127&amp;sn=2444814c391550245cc0b959da897f8f#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="karpathy编程经验开源-star疯涨" tabindex="-1"><a class="header-anchor" href="#karpathy编程经验开源-star疯涨"><span>Karpathy编程经验开源，Star疯涨！</span></a></h3><p>Karpathy编程经验开源项目周末爆火，将其对大模型写代码问题编译成约束。当下行业把人的经验编译成Agent可执行格式，开源范式转变，写规则、审美未来或成产品。<a href="https://mp.weixin.qq.com/s?__biz=MzkxNjcyNTk2NA==&amp;chksm=c0201924ac4105e93c592f5054d6fa2679358132404850c6014e433c93050a352759df677127&amp;idx=1&amp;mid=2247492195&amp;sn=f5b564bae98a481c041aa165e57f4ded#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="openbmb推多语言语音合成系统voxcpm2" tabindex="-1"><a class="header-anchor" href="#openbmb推多语言语音合成系统voxcpm2"><span>OpenBMB推多语言语音合成系统VoxCPM2</span></a></h3><p>OpenBMB：推出VoxCPM2语音合成系统，支持30种语言与9种中文方言，能进行音色设计和声音克隆，还可微调，全开源且支持商用，部署推理速度快。<a href="https://mp.weixin.qq.com/s?__biz=MzkxNjQ4MzMyOA==&amp;chksm=c05c295b6d41d5993b8278b41e07ed24cd0344951b8557eb60279cbfcbd9f25c1c0c05c015ac&amp;idx=1&amp;mid=2247495078&amp;sn=571b7190f042d01d06ae7059cec9ee8c#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h2 id="算法论文" tabindex="-1"><a class="header-anchor" href="#算法论文"><span>算法论文</span></a></h2><h3 id="同济kc-vla治好了vla大模型的-健忘症" tabindex="-1"><a class="header-anchor" href="#同济kc-vla治好了vla大模型的-健忘症"><span>同济KC - VLA治好了VLA大模型的“健忘症”</span></a></h3><p>同济团队：现有VLA大模型处理长任务易断片，提出KC - VLA框架，通过关键帧链让机器人有全局时间感知能力，构建基准测试，实验证明其性能远超传统模型。<a href="https://mp.weixin.qq.com/s?__biz=Mzk0MTYzMzMxMA==&amp;chksm=c3b2c608c354d4494e984bf0099cf17fe154c0ea2a400024c39176ccf1ab43f89115792c4cbc&amp;idx=2&amp;mid=2247506473&amp;sn=d6538da357ed83b9e85bc265d5351457#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="autoresearchclaw-ai自主设计记忆系统性能飙升" tabindex="-1"><a class="header-anchor" href="#autoresearchclaw-ai自主设计记忆系统性能飙升"><span>AutoResearchClaw：AI自主设计记忆系统性能飙升</span></a></h3><p>北卡罗来纳大学等团队：用AutoResearchClaw让AI自主设计多模态记忆系统OMNIMEM，72小时完成重构，性能提升超400%，全面碾压现有系统，开启机器指导机器进化新阶段。<a href="https://mp.weixin.qq.com/s?__biz=Mzg3Mzg5MjY3Nw==&amp;chksm=cfd233a52ff8c5a4614283dbc190bf93e0dfbc1eb3d2afac1c19baf87ef5ed6ba2e940f5a663&amp;idx=3&amp;mid=2247526127&amp;sn=9f7f235868a0d6d80dcd0930e8aab5ed#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="上交大等-llm-agents外部化统一综述" tabindex="-1"><a class="header-anchor" href="#上交大等-llm-agents外部化统一综述"><span>上交大等：LLM Agents外部化统一综述</span></a></h3><p>上交大等团队：LLM Agents能力迁移历经权重、上下文、Harness时代。记忆、技能、协议外部化解决不同负担，Harness工程承载三者，模块间存在耦合。<a href="https://mp.weixin.qq.com/s?__biz=Mzk0MTYzMzMxMA==&amp;chksm=c31dd469e168e8419bfd04bce5cc159922439eefd8b060e781a3488c20c7734ae88a70350690&amp;idx=1&amp;mid=2247506473&amp;sn=23d3025038c61e750a31131efac2c6da#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="南大傅朝友发布-video-mme-v2-挤干模型高分水分" tabindex="-1"><a class="header-anchor" href="#南大傅朝友发布-video-mme-v2-挤干模型高分水分"><span>南大傅朝友发布 Video-MME-v2 挤干模型高分水分</span></a></h3><p>南大傅朝友团队推出 Video-MME-v2 评测基准。它用分层能力体系和组级非线性评分，发现最强商业模型 Gemini-3-Pro 得分 49.4，与人类差距大，还揭示 “Thinking” 不总有效。<a href="https://mp.weixin.qq.com/s?__biz=MzA3MzI4MjgzMw==&amp;chksm=8588c3f4270e2e1698e07bdaefbdab10b3f9ca04b3627b77a911e8a730019acc38076854fd02&amp;idx=1&amp;mid=2651027200&amp;sn=871567c18390b4a7d54c4cf247399900#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><p style="text-align:center;"><img id="weixin_qr" src="https://meikan-public-images.oss-cn-beijing.aliyuncs.com/imeikan/assets/2025-05-18234303-hub.png" style="max-width:800px;object-fit:cover;"></p><p><a href="https://aireadinghub.com/" target="_blank" rel="noopener noreferrer">官网：www.AiReadingHub.com</a></p>',59)]))}const l=a(c,[["render",t]]),p=JSON.parse('{"path":"/posts/2026-04-13.html","title":"AI日报：美国报告：中国开源模型超越美国; 97小伙余琛研发可断腿奔跑的模块化机器人; 奥特曼豪宅再遭袭，AI末日论者发难","lang":"zh-CN","frontmatter":{"date":"2026-04-13T00:00:00.000Z","title":"AI日报：美国报告：中国开源模型超越美国; 97小伙余琛研发可断腿奔跑的模块化机器人; 奥特曼豪宅再遭袭，AI末日论者发难"},"headers":[{"level":2,"title":"新闻资讯","slug":"新闻资讯","link":"#新闻资讯","children":[{"level":3,"title":"美国报告：中国开源模型超越美国","slug":"美国报告-中国开源模型超越美国","link":"#美国报告-中国开源模型超越美国","children":[]},{"level":3,"title":"97小伙余琛研发可断腿奔跑的模块化机器人","slug":"_97小伙余琛研发可断腿奔跑的模块化机器人","link":"#_97小伙余琛研发可断腿奔跑的模块化机器人","children":[]},{"level":3,"title":"奥特曼豪宅再遭袭，AI末日论者发难","slug":"奥特曼豪宅再遭袭-ai末日论者发难","link":"#奥特曼豪宅再遭袭-ai末日论者发难","children":[]},{"level":3,"title":"自变量：戳破具身智能行业‘气泡’","slug":"自变量-戳破具身智能行业-气泡","link":"#自变量-戳破具身智能行业-气泡","children":[]},{"level":3,"title":"Hermes Agent爆火，新推理方法问世","slug":"hermes-agent爆火-新推理方法问世","link":"#hermes-agent爆火-新推理方法问世","children":[]},{"level":3,"title":"极佳视界获大额融资，领跑世界模型赛道","slug":"极佳视界获大额融资-领跑世界模型赛道","link":"#极佳视界获大额融资-领跑世界模型赛道","children":[]}]},{"level":2,"title":"产品应用","slug":"产品应用","link":"#产品应用","children":[{"level":3,"title":"Claude Code省Token指南大揭秘","slug":"claude-code省token指南大揭秘","link":"#claude-code省token指南大揭秘","children":[]},{"level":3,"title":"LibTV支持Seedance 2.0真人模式，效果炸裂","slug":"libtv支持seedance-2-0真人模式-效果炸裂","link":"#libtv支持seedance-2-0真人模式-效果炸裂","children":[]},{"level":3,"title":"明略 Mano-P 1.0：引领个性化 AI 新时代","slug":"明略-mano-p-1-0-引领个性化-ai-新时代","link":"#明略-mano-p-1-0-引领个性化-ai-新时代","children":[]},{"level":3,"title":"AI Agent应用：理想美好，现实骨感","slug":"ai-agent应用-理想美好-现实骨感","link":"#ai-agent应用-理想美好-现实骨感","children":[]},{"level":3,"title":"Harness Monitor：看住多 Agent 代码质量","slug":"harness-monitor-看住多-agent-代码质量","link":"#harness-monitor-看住多-agent-代码质量","children":[]}]},{"level":2,"title":"推荐文章","slug":"推荐文章","link":"#推荐文章","children":[{"level":3,"title":"Tokens烧钱？四层模型组合来救场","slug":"tokens烧钱-四层模型组合来救场","link":"#tokens烧钱-四层模型组合来救场","children":[]},{"level":3,"title":"卡兹克：横纵分析法半小时搞懂陌生领域","slug":"卡兹克-横纵分析法半小时搞懂陌生领域","link":"#卡兹克-横纵分析法半小时搞懂陌生领域","children":[]},{"level":3,"title":"学者解析Coding Agent底层逻辑","slug":"学者解析coding-agent底层逻辑","link":"#学者解析coding-agent底层逻辑","children":[]},{"level":3,"title":"Hermes-Agent：实现Agent自学习新突破","slug":"hermes-agent-实现agent自学习新突破","link":"#hermes-agent-实现agent自学习新突破","children":[]}]},{"level":2,"title":"开源动态","slug":"开源动态","link":"#开源动态","children":[{"level":3,"title":"Hermes Agent：比OpenClaw更快更灵活的AI Agent","slug":"hermes-agent-比openclaw更快更灵活的ai-agent","link":"#hermes-agent-比openclaw更快更灵活的ai-agent","children":[]},{"level":3,"title":"黄叔开源Skill管理神器Skill Hub","slug":"黄叔开源skill管理神器skill-hub","link":"#黄叔开源skill管理神器skill-hub","children":[]},{"level":3,"title":"飞樰深度解析OpenClaw设计哲学","slug":"飞樰深度解析openclaw设计哲学","link":"#飞樰深度解析openclaw设计哲学","children":[]},{"level":3,"title":"AutoSOTA：让科研摆脱“增量式优化”","slug":"autosota-让科研摆脱-增量式优化","link":"#autosota-让科研摆脱-增量式优化","children":[]},{"level":3,"title":"Karpathy编程经验开源，Star疯涨！","slug":"karpathy编程经验开源-star疯涨","link":"#karpathy编程经验开源-star疯涨","children":[]},{"level":3,"title":"OpenBMB推多语言语音合成系统VoxCPM2","slug":"openbmb推多语言语音合成系统voxcpm2","link":"#openbmb推多语言语音合成系统voxcpm2","children":[]}]},{"level":2,"title":"算法论文","slug":"算法论文","link":"#算法论文","children":[{"level":3,"title":"同济KC - VLA治好了VLA大模型的“健忘症”","slug":"同济kc-vla治好了vla大模型的-健忘症","link":"#同济kc-vla治好了vla大模型的-健忘症","children":[]},{"level":3,"title":"AutoResearchClaw：AI自主设计记忆系统性能飙升","slug":"autoresearchclaw-ai自主设计记忆系统性能飙升","link":"#autoresearchclaw-ai自主设计记忆系统性能飙升","children":[]},{"level":3,"title":"上交大等：LLM Agents外部化统一综述","slug":"上交大等-llm-agents外部化统一综述","link":"#上交大等-llm-agents外部化统一综述","children":[]},{"level":3,"title":"南大傅朝友发布 Video-MME-v2 挤干模型高分水分","slug":"南大傅朝友发布-video-mme-v2-挤干模型高分水分","link":"#南大傅朝友发布-video-mme-v2-挤干模型高分水分","children":[]}]}],"git":{"updatedTime":1777092691000,"contributors":[{"name":"GitHub Actions","username":"","email":"actions@github.com","commits":1}],"changelog":[{"hash":"6af32efb45b34c508f94ab48f1efc3c2ce851e30","time":1777092691000,"email":"actions@github.com","author":"GitHub Actions","message":"Auto-commit generated files on 2026-04-25T04:51:31.794Z"}]},"filePathRelative":"posts/2026-04-13.md","excerpt":"<blockquote>\\n<p>All in AI，看见未来。 每天精选最值得读的AI文章，帮你筛掉时代的噪音。 以简讯见广度，以深读见洞察。 技术、趋势、思考，一站式掌握AI世界。\\n欢迎关注公众号「AI Reading Hub」，获取更多AI资讯和技术文章。</p>\\n</blockquote>\\n<h1>2026-04-13 资讯日报</h1>\\n<h2>新闻资讯</h2>\\n<h3>美国报告：中国开源模型超越美国</h3>\\n<p>美国ATOM报告：2025年夏中国开源语言模型全面超越美国，下载、使用量优势明显。Qwen称霸，DeepSeek在大模型领域领先。美国新势力追赶，报告引入新指标评模型热度。<a href=\\"https://mp.weixin.qq.com/s?__biz=Mzg3Mzg5MjY3Nw==&amp;chksm=cf3dd83aa348f1faccaf1f2bdd99f6e22712bde3647c9f8e6c751112969205f3c098bde79452&amp;idx=1&amp;mid=2247526127&amp;sn=e62cf6ad26268c401fec898094de4810#rd\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">&gt;阅读原文</a></p>"}');export{l as comp,p as data};
